SELECT DISTINCT m.state, m.district, c.city
FROM members m
INNER JOIN constituencies c ON m.state = c.state AND m.district = c.district;

SELECT COUNT(DISTINCT member_id)
FROM missed_votes
WHERE missed_date IS NOT NULL AND reason IS NOT NULL;

SELECT COUNT(*) AS total_missed_votes
FROM missed_votes
WHERE member_id = '0' AND session_id = 1;

SELECT DISTINCT T1.district
FROM constituencies AS T1
WHERE T1.population > (SELECT AVG(population) FROM constituencies);
